mapper.select:
/* wms-ctmaster-area-sql-oracle.xml - selectAreaList */
SELECT '0' AS CHK , AR.CTKEY , CT.CTNM , AR.ZNKEY , ZN.ZNNM , AR.ARKEY , AR.ARNM , AR.ICTMPRDIVCD , AR.BNDDIVCD , AR.ARDIVCD , AR.WRHOUSDIVCD , AR.ANSUNGB2BPOCTG , AR.NAMSAB2BPOCTG , AR.BUSANB2BPOCTG , AR.SEJONGB2BPOCTG , AR.INSERTDATE , AR.INSERTURKEY , AR.UPDATEDATE , AR.UPDATEURKEY
ORDER BY ZN.ZNTYPECD , AR.UPDATEDATE DESC

/* wms-ctmaster-area-sql-oracle.xml - selectAreaDupCheck */
SELECT COUNT(1)
  FROM TWORK_MST_AR


	AND CTKEY = #{ctkey}
	AND ZNKEY = #{znkey}
	AND ARKEY = #{arkey}

/* wms-ctmaster-area-sql-oracle.xml - selectAreaUseCheckCount */
SELECT COUNT(1) AS CNT
  FROM TWORK_MST_LC
 WHERE CTKEY = #{ctkey}
   AND ZNKEY = #{znkey}
   AND ARKEY = #{arkey}

mapper.insert:
/* wms-ctmaster-area-sql-oracle.xml - insertArea */
INSERT INTO TWORK_MST_AR (
	   CTKEY
	 , ZNKEY
	 , ARKEY
	 , ARNM
	 , ICTMPRDIVCD
	 , WRHOUSDIVCD
	 , ANSUNGB2BPOCTG
	 , NAMSAB2BPOCTG
	 , BUSANB2BPOCTG
	 , SEJONGB2BPOCTG
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
)
VALUES (
	   #{ctkey}
	 , #{znkey}
	 , #{arkey}
	 , #{arnm}
	 , #{ictmprdivcd}
	 , #{wrhousdivcd}
	 , #{ansungb2bpoctg}
	 , #{namsab2bpoctg}
	 , #{busanb2bpoctg}
	 , #{sejongb2bpoctg}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

mapper.update:
/* wms-ctmaster-area-sql-oracle.xml - updateArea */
UPDATE TWORK_MST_AR
   SET ARNM = #{arnm}
	 , WRHOUSDIVCD = #{wrhousdivcd}
     , ANSUNGB2BPOCTG = #{ansungb2bpoctg}
	 , NAMSAB2BPOCTG = #{namsab2bpoctg}
	 , BUSANB2BPOCTG = #{busanb2bpoctg}
	 , SEJONGB2BPOCTG = #{sejongb2bpoctg}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND ZNKEY = #{znkey}
   AND ARKEY = #{arkey}

mapper.delete:
/* wms-ctmaster-area-sql-oracle.xml - deleteArea */
DELETE
  FROM TWORK_MST_AR
WHERE CTKEY = #{ctkey}
  AND ZNKEY = #{znkey}
  AND ARKEY = #{arkey}
